import { Outlet, NavLink, Link, useNavigate, useLocation } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import React, { useState, useEffect, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { io } from 'socket.io-client'
import toast from 'react-hot-toast'
import {
    HiHome, HiSearch, HiFilm, HiChatAlt2,
    HiBell, HiLogout, HiPlusCircle, HiCog, HiMenu, HiMoon, HiSun, HiUser
} from 'react-icons/hi'
import { FaLinkedin } from 'react-icons/fa'
import { useTheme } from '../context/ThemeContext'
import api, { SOCKET_URL } from '../api/axios'
import CreatePostModal from './CreatePostModal'
import ThemeToggle from './ThemeToggle'
import logoImg from '../assets/logo.png'

// Instagram-style nav: filled icon always, inactive = 0.55 opacity, active = full + bold
const links = [
    { to: '/', icon: HiHome, label: 'Home', exact: true },
    { to: '/search', icon: HiSearch, label: 'Search' },
    { to: '/dscrolls', icon: HiFilm, label: 'Dscrolls' },
    { to: '/messages', icon: HiChatAlt2, label: 'Messages', msgBadge: true },
    { to: '/notifications', icon: HiBell, label: 'Notifications', badge: true },
]

const mobileBottomLinksLeft = [
    { to: '/', icon: HiHome, exact: true },
    { to: '/search', icon: HiSearch },
]

const mobileBottomLinksRight = [
    { to: '/dscrolls', icon: HiFilm },
]

let layoutSocket = null


export default function Layout() {
    const { user, logout } = useAuth()
    const { isDark } = useTheme()
    const navigate = useNavigate()
    const location = useLocation()
    const [showCreate, setShowCreate] = useState(false)
    const [unreadCount, setUnreadCount] = useState(0)
    const [msgCount, setMsgCount] = useState(0)
    const [isCollapsed] = useState(false)
    const unreadRef = useRef(0)
    const msgRef = useRef(0)
    const mainRef = useRef(null)

    // ΓöÇΓöÇ Scroll to top on route change ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    useEffect(() => {
        if (mainRef.current) mainRef.current.scrollTo({ top: 0, behavior: 'instant' })
    }, [location.pathname])

    // ΓöÇΓöÇ Fetch initial unread notification count + polling fallback ΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Polls every 30s so badge updates even if socket/Redis is down
    useEffect(() => {
        if (!user) return

        const syncNotifCount = () => {
            api.get('/notifications?limit=1')
                .then(({ data }) => {
                    const serverCount = data.unreadCount || 0
                    if (serverCount > unreadRef.current) {
                        // Server has MORE unread than we know about ΓåÆ bump badge (polling delivered it)
                        setUnreadCount(serverCount)
                        unreadRef.current = serverCount
                    } else if (serverCount < unreadRef.current) {
                        // They read on another tab/device
                        setUnreadCount(serverCount)
                        unreadRef.current = serverCount
                    }
                })
                .catch(() => { })
        }

        syncNotifCount()                           // immediate
        const poll = setInterval(syncNotifCount, 30_000)   // every 30s fallback
        return () => clearInterval(poll)
    }, [user])

    // ΓöÇΓöÇ Real-time socket notifications ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    useEffect(() => {
        const token = localStorage.getItem('accessToken')
        if (!token || !user) return

        const showNotifToast = (notif) => {
            const typeEmoji = { like: 'Γ¥ñ∩╕Å', comment: '≡ƒÆ¼', follow: '≡ƒæñ', message: '≡ƒÆ¼' }
            const typeText = { like: 'liked your post', comment: 'commented on your post', follow: 'started following you' }
            const typeColor = { like: '#FF375F', comment: '#6366F1', follow: '#10B981' }
            const color = typeColor[notif.type] || '#6366F1'

            toast((t) => (
                <div
                    onClick={() => { navigate('/notifications'); toast.dismiss(t.id) }}
                    style={{ display: 'flex', alignItems: 'center', gap: 12, cursor: 'pointer', padding: '2px 4px' }}
                >
                    <div style={{ position: 'relative', flexShrink: 0 }}>
                        <img
                            src={notif.sender?.avatarUrl || `https://ui-avatars.com/api/?name=${notif.sender?.username}&background=6366F1&color=fff`}
                            style={{ width: 40, height: 40, borderRadius: '50%', objectFit: 'cover', display: 'block' }}
                            alt=""
                        />
                        <div style={{
                            position: 'absolute', bottom: -2, right: -2,
                            width: 18, height: 18, borderRadius: '50%',
                            background: color,
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            fontSize: 10, border: '2px solid var(--surface)',
                        }}>{typeEmoji[notif.type]}</div>
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                        <p style={{ margin: 0, fontSize: 13, fontWeight: 700, color: 'var(--text-1)', lineHeight: 1.3 }}>
                            {notif.sender?.username}
                            <span style={{ fontWeight: 400, color: 'var(--text-2)', marginLeft: 4 }}>{typeText[notif.type]}</span>
                        </p>
                        <p style={{ margin: '2px 0 0', fontSize: 11, color: 'var(--text-3)' }}>Tap to view</p>
                    </div>
                </div>
            ), {
                duration: 5000,
                style: {
                    background: 'var(--surface)', color: 'var(--text-1)',
                    border: '1px solid var(--border-md)', borderRadius: 16,
                    boxShadow: '0 8px 32px rgba(0,0,0,0.25)', backdropFilter: 'blur(20px)',
                    padding: '12px 16px', maxWidth: 340,
                },
            })
        }

        const showMsgToast = (msg) => {
            const senderName = msg.sender?.username || 'Someone'
            const senderAvatar = msg.sender?.avatarUrl || `https://ui-avatars.com/api/?name=${senderName}&background=6366F1&color=fff`
            const convoId = msg.conversationId
            const preview = msg.body?.length > 40 ? msg.body.slice(0, 40) + 'ΓÇª' : (msg.body || '≡ƒô╖ Photo')

            toast((t) => (
                <div
                    onClick={() => { navigate(`/messages/${convoId || ''}`); toast.dismiss(t.id) }}
                    style={{ display: 'flex', alignItems: 'center', gap: 12, cursor: 'pointer', padding: '2px 4px' }}
                >
                    <div style={{ position: 'relative', flexShrink: 0 }}>
                        <img src={senderAvatar} style={{ width: 40, height: 40, borderRadius: '50%', objectFit: 'cover', display: 'block' }} alt="" />
                        <div style={{
                            position: 'absolute', bottom: -2, right: -2, width: 18, height: 18, borderRadius: '50%',
                            background: 'linear-gradient(135deg,#6366F1,#A78BFA)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            fontSize: 9, border: '2px solid var(--surface)',
                        }}>≡ƒÆ¼</div>
                    </div>
                    <div style={{ flex: 1, minWidth: 0 }}>
                        <p style={{ margin: 0, fontSize: 13, fontWeight: 700, color: 'var(--text-1)', lineHeight: 1.3 }}>{senderName}</p>
                        <p style={{ margin: '2px 0 0', fontSize: 12, color: 'var(--text-3)', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', maxWidth: 180 }}>{preview}</p>
                    </div>
                    <div style={{ width: 8, height: 8, borderRadius: '50%', background: '#6366F1', flexShrink: 0, boxShadow: '0 0 6px #6366F1' }} />
                </div>
            ), {
                duration: 6000,
                style: {
                    background: 'var(--surface)', color: 'var(--text-1)',
                    border: '1px solid var(--border-md)', borderRadius: 16,
                    boxShadow: '0 8px 32px rgba(0,0,0,0.25)', backdropFilter: 'blur(20px)',
                    padding: '12px 16px', maxWidth: 340,
                },
            })
        }

        layoutSocket = io(SOCKET_URL, {
            auth: { token },
            path: '/socket.io',
            transports: ['websocket', 'polling'],
            reconnection: true,
            reconnectionAttempts: Infinity,
            reconnectionDelay: 1500,
            reconnectionDelayMax: 10000,
        })

        layoutSocket.on('connect', () => {
            // Re-sync counts after reconnect (e.g. Render cold-start, tab wake)
            api.get('/notifications?limit=1').then(({ data }) => {
                const c = data.unreadCount || 0
                unreadRef.current = c
                setUnreadCount(c)
            }).catch(() => { })
        })

        layoutSocket.on('connect_error', (err) => {
            console.warn('[Socket] Connection error:', err.message)
        })

        layoutSocket.on('new_notification', (notif) => {
            unreadRef.current += 1
            setUnreadCount(unreadRef.current)
            showNotifToast(notif)
        })

        layoutSocket.on('new_message', (msg) => {
            // FIX: compare IDs as strings ΓÇö sender may be ObjectId from backend
            const senderId = (msg.sender?._id || msg.sender || '').toString()
            const myId = (user?._id || '').toString()
            if (senderId === myId) return  // skip own sent messages

            if (!window.location.pathname.startsWith('/messages')) {
                msgRef.current += 1
                setMsgCount(c => c + 1)
                showMsgToast(msg)
            } else {
                // Still update badge in sidebar even when on messages (different convo)
                msgRef.current += 1
                setMsgCount(c => c + 1)
            }
        })

        return () => { layoutSocket?.disconnect(); layoutSocket = null }
    }, [user, navigate])

    // ΓöÇΓöÇ Clear badges when actually ON the relevant page ΓöÇΓöÇΓöÇΓöÇ
    useEffect(() => {
        if (location.pathname === '/notifications') {
            setUnreadCount(0)
            unreadRef.current = 0
        }
        if (location.pathname.startsWith('/messages')) {
            setMsgCount(0)
            msgRef.current = 0
        }
    }, [location.pathname])

    const handleNavClick = () => { } // retained for any future use

    const handleLogout = async () => {
        await logout()
        navigate('/login')
    }

    const avatarUrl = user?.avatarUrl || `https://ui-avatars.com/api/?name=${user?.username}&background=6366F1&color=fff`

    const [showMore, setShowMore] = useState(false)
    const moreRef = useRef(null)

    // Close "More" popup when clicking outside
    useEffect(() => {
        if (!showMore) return
        const handler = (e) => { if (moreRef.current && !moreRef.current.contains(e.target)) setShowMore(false) }
        document.addEventListener('mousedown', handler)
        return () => document.removeEventListener('mousedown', handler)
    }, [showMore])

    return (
        <div className={`app-layout ${isCollapsed ? 'sidebar-collapsed' : ''}`}>
            {/* ΓöÇΓöÇ Sidebar ΓöÇΓöÇ */}
            <aside className={`sidebar ${isCollapsed ? 'collapsed' : ''}`}>

                {/* Logo row */}
                <div className="sidebar-logo-row">
                    {!isCollapsed ? (
                        <Link to="/" className="sidebar-brand">
                            <img src={logoImg} alt="PeerNet" className="sidebar-brand-img" />
                            <span className="peernetLogo">PeerNet</span>
                        </Link>
                    ) : (
                        <Link to="/" className="sidebar-brand sidebar-brand--collapsed">
                            <img src={logoImg} alt="PeerNet" className="sidebar-brand-img" />
                        </Link>
                    )}
                </div>

                {/* Main nav */}
                <nav className="sidebar-nav">
                    {links.map(({ to, icon: Icon, label, exact, badge, msgBadge }) => (
                        <NavLink key={to} to={to} end={exact}
                            className={({ isActive }) => `ig-link ${isActive ? 'ig-link--active' : ''}`}>
                            {({ isActive }) => (
                                <>
                                    <span className="ig-icon-wrap" style={{ position: 'relative' }}>
                                        <Icon className="ig-icon" style={{ opacity: isActive ? 1 : 0.55 }} />
                                        {badge && unreadCount > 0 && (
                                            <motion.span className="ig-badge" initial={{ scale: 0 }} animate={{ scale: 1 }}>
                                                {unreadCount > 9 ? '9+' : unreadCount}
                                            </motion.span>
                                        )}
                                        {msgBadge && msgCount > 0 && (
                                            <motion.span className="ig-badge ig-badge--msg" initial={{ scale: 0 }} animate={{ scale: 1 }}>
                                                {msgCount > 9 ? '9+' : msgCount}
                                            </motion.span>
                                        )}
                                    </span>
                                    <span className="ig-label">{label}</span>
                                </>
                            )}
                        </NavLink>
                    ))}

                    {/* Create */}
                    <button className="ig-link" onClick={() => setShowCreate(true)}>
                        <span className="ig-icon-wrap">
                            <HiPlusCircle className="ig-icon" style={{ opacity: 0.55 }} />
                        </span>
                        <span className="ig-label">Create</span>
                    </button>

                    {/* Profile */}
                    <NavLink to={`/profile/${user?._id}`}
                        className={({ isActive }) => `ig-link ${isActive ? 'ig-link--active' : ''}`}>
                        {({ isActive }) => (
                            <>
                                <span className="ig-icon-wrap">
                                    <img src={avatarUrl} alt=""
                                        className="ig-avatar"
                                        style={{ outline: isActive ? '2px solid var(--text-1)' : '2px solid transparent' }} />
                                </span>
                                <span className="ig-label">Profile</span>
                            </>
                        )}
                    </NavLink>
                </nav>

                {/* More button ΓÇö bottom */}
                <div className="sidebar-more-wrap" ref={moreRef}>
                    <AnimatePresence>
                        {showMore && (
                            <motion.div className="ig-more-popup"
                                initial={{ opacity: 0, y: 8, scale: 0.96 }}
                                animate={{ opacity: 1, y: 0, scale: 1 }}
                                exit={{ opacity: 0, y: 8, scale: 0.96 }}
                                transition={{ duration: 0.15 }}>
                                <button className="ig-more-item" onClick={() => { document.querySelector('.theme-toggle')?.click(); setShowMore(false) }}>
                                    <ThemeToggle className="sr-only" />
                                    {isDark ? <HiSun style={{ fontSize: 20 }} /> : <HiMoon style={{ fontSize: 20 }} />}
                                    <span>Switch appearance</span>
                                </button>
                                <NavLink to="/settings" className="ig-more-item" onClick={() => setShowMore(false)}>
                                    <HiCog style={{ fontSize: 20 }} />
                                    <span>Settings</span>
                                </NavLink>
                                <div className="ig-more-divider" />
                                <button className="ig-more-item ig-more-item--danger" onClick={handleLogout}>
                                    <HiLogout style={{ fontSize: 20 }} />
                                    <span>Log out</span>
                                </button>
                            </motion.div>
                        )}
                    </AnimatePresence>

                    <button className={`ig-link ${showMore ? 'ig-link--active' : ''}`}
                        onClick={() => setShowMore(v => !v)}
                        style={{ width: '100%' }}>
                        <span className="ig-icon-wrap">
                            <HiMenu className="ig-icon" />
                        </span>
                        <span className="ig-label">More</span>
                    </button>
                </div>
            </aside>

            {/* ΓöÇΓöÇ Main ΓöÇΓöÇ */}
            <main className="main-col" ref={mainRef} style={{ overflowY: 'auto', height: '100dvh' }}>
                {/* ΓöÇΓöÇ Mobile Top Header ΓöÇΓöÇ */}
                <header className="mobile-top-header">
                    <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 8 }}>
                        <img src={logoImg} alt="PeerNet" style={{ width: 28, height: 28, objectFit: 'contain', borderRadius: 8 }} />
                        <span style={{ fontFamily: "'Syne', 'Inter', sans-serif", fontWeight: 800, fontSize: 18, background: 'var(--logo-gradient)', WebkitBackgroundClip: 'text', color: 'transparent' }}>PeerNet</span>
                    </Link>
                    <div className="mobile-top-actions">
                        <NavLink to="/notifications" className={({ isActive }) => isActive ? 'active' : ''} style={{ position: 'relative' }}>
                            <HiBell />
                            {unreadCount > 0 && (
                                <span className="mobile-badge" style={{ background: 'var(--error)' }}>
                                    {unreadCount > 9 ? '9+' : unreadCount}
                                </span>
                            )}
                        </NavLink>
                        <NavLink to="/messages" className={({ isActive }) => isActive ? 'active' : ''} style={{ position: 'relative' }}>
                            <HiChatAlt2 />
                            {msgCount > 0 && (
                                <span className="mobile-badge" style={{ background: 'var(--accent)' }}>
                                    {msgCount > 9 ? '9+' : msgCount}
                                </span>
                            )}
                        </NavLink>
                    </div>
                </header>

                <div className="content-wrap">
                    <AnimatePresence mode="wait">
                        <Outlet />
                    </AnimatePresence>
                </div>

                {/* ΓöÇΓöÇ Footer ΓöÇΓöÇ */}
                <footer className="site-footer">
                    <div className="site-footer__inner">
                        <span className="site-footer__brand">PeerNet</span>
                        <span className="site-footer__divider">┬╖</span>
                        <span className="site-footer__text">Built by</span>
                        <a
                            href="https://www.linkedin.com/in/syedmukheeth"
                            target="_blank"
                            rel="noopener noreferrer"
                            className="site-footer__link"
                        >
                            Syed Mukheeth
                        </a>
                    </div>
                </footer>
            </main>

            <nav className="mobile-nav">
                {mobileBottomLinksLeft.map(({ to, icon: Icon, exact }) => (
                    <NavLink key={to} to={to} end={exact} onClick={() => handleNavClick(to)}
                        className={({ isActive }) => isActive ? 'active' : ''}>
                        <div style={{ position: 'relative' }}>
                            <Icon />
                        </div>
                    </NavLink>
                ))}

                {/* Centre: Create button */}
                <button onClick={() => setShowCreate(true)}
                    style={{ background: 'none', border: '1px solid var(--border-md)', borderRadius: 12, width: 34, height: 34, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: 'var(--text-1)', fontSize: 24, fontWeight: 300, lineHeight: 1 }}>
                    <HiPlusCircle style={{ fontSize: 28 }} />
                </button>

                {mobileBottomLinksRight.map(({ to, icon: Icon, exact }) => (
                    <NavLink key={to} to={to} end={exact} onClick={() => handleNavClick(to)}
                        className={({ isActive }) => isActive ? 'active' : ''}>
                        <div style={{ position: 'relative' }}>
                            <Icon />
                        </div>
                    </NavLink>
                ))}

                <NavLink to={`/profile/${user?._id}`}
                    className={({ isActive }) => isActive ? 'active' : ''}>
                    <HiUser />
                </NavLink>
            </nav>

            {showCreate && <CreatePostModal onClose={() => setShowCreate(false)} />}
        </div>
    )
}

import React from 'react';
import { render } from '@testing-library/react';
import { PostSkeleton, StorySkeleton } from '../SkeletonLoader';

describe('SkeletonLoader Components', () => {
    describe('PostSkeleton', () => {
        it('should render without crashing', () => {
            const { container } = render(<PostSkeleton />);
            expect(container.querySelector('.shimmer')).toBeInTheDocument();
            expect(container.querySelector('.skeleton-card')).toBeInTheDocument();
            expect(container.querySelector('.skeleton-header')).toBeInTheDocument();
        });
    });

    describe('StorySkeleton', () => {
        it('should render 6 skeleton items by default', () => {
            const { container } = render(<StorySkeleton />);
            const items = container.querySelectorAll('.skeleton-story-item');
            expect(items.length).toBe(6);
            expect(container.querySelector('.skeleton-story-rail')).toBeInTheDocument();
        });
    });
});

import { useState, useEffect, useRef } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import api, { SOCKET_URL, CHAT_BASE_URL } from '../api/axios'
import { io } from 'socket.io-client'
import { HiBadgeCheck, HiSearch, HiX, HiPencilAlt, HiArrowLeft, HiPhotograph, HiEmojiHappy, HiDocument, HiDownload, HiPaperAirplane, HiTrash } from 'react-icons/hi'
import { timeago } from '../utils/timeago'
import toast from 'react-hot-toast'
import EmojiPicker from 'emoji-picker-react'

let socket = null

/* ΓöÇΓöÇ Skeletons ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function MessageSkeleton() {
    return (
        <div style={{ display: 'flex', gap: 12, padding: '10px 0', opacity: 0.6, animation: 'pulse 1.5s infinite' }}>
            <div style={{ width: 36, height: 36, borderRadius: '50%', background: 'var(--border-md)' }} />
            <div style={{ flex: 1 }}>
                <div style={{ width: 120, height: 16, borderRadius: 4, background: 'var(--border-md)', marginBottom: 8 }} />
                <div style={{ width: '60%', height: 14, borderRadius: 4, background: 'var(--border)', marginBottom: 4 }} />
                <div style={{ width: '40%', height: 14, borderRadius: 4, background: 'var(--border)' }} />
            </div>
        </div>
    )
}

/* ΓöÇΓöÇ Typing Bubbles ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function TypingBubble() {
    return (
        <div style={{ display: 'flex', alignItems: 'flex-end', gap: 8, padding: '2px 0' }}>
            <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'var(--hover)', flexShrink: 0 }} />
            <div style={{
                display: 'flex', gap: 4, padding: '12px 16px',
                background: 'var(--dm-theirs)', borderRadius: 22, borderBottomLeftRadius: 4,
                width: 56,
            }}>
                {[0, 200, 400].map((d, i) => (
                    <span key={i} style={{
                        width: 7, height: 7, borderRadius: '50%',
                        background: 'var(--text-3)', display: 'block',
                        animation: `pulseDot 1.2s ease-in-out ${d}ms infinite`,
                    }} />
                ))}
            </div>
        </div>
    )
}

/* ΓöÇΓöÇ New Message Modal ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function NewConvoModal({ onClose, onStart }) {
    const [q, setQ] = useState('')
    const [results, setResults] = useState([])
    const [loading, setLoading] = useState(false)

    const search = async (e) => {
        const v = e.target.value; setQ(v)
        if (v.length < 2) return setResults([])
        setLoading(true)
        try { const { data } = await api.get('/users/search', { params: { q: v, limit: 15 } }); setResults(data.data || []) }
        catch (err) { console.error("Search error:", err) } finally { setLoading(false) }
    }

    return (
        <div className="modal-overlay" onClick={onClose}>
            <div onClick={e => e.stopPropagation()} style={{
                background: 'var(--surface)', borderRadius: 16,
                width: '100%', maxWidth: 400,
                border: '1px solid var(--border-md)',
                boxShadow: 'var(--shadow-lg)', overflow: 'hidden',
            }}>
                <div style={{ padding: '18px 20px', borderBottom: '1px solid var(--border)', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <span style={{ fontWeight: 700, fontSize: 16 }}>New message</span>
                    <button onClick={onClose} style={{ background: 'none', border: 'none', color: 'var(--text-2)', cursor: 'pointer', fontSize: 20, display: 'flex', alignItems: 'center' }}><HiX /></button>
                </div>
                <div style={{ padding: '10px 16px', borderBottom: '1px solid var(--border)', display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span style={{ color: 'var(--text-3)', fontSize: 14 }}>To:</span>
                    <input
                        autoFocus value={q} onChange={search}
                        placeholder="Search..."
                        style={{
                            flex: 1, background: 'none', border: 'none',
                            outline: 'none', color: 'var(--text-1)', fontSize: 14,
                        }} />
                    {loading && <div className="spinner" style={{ width: 14, height: 14 }} />}
                </div>
                <div style={{ maxHeight: 320, overflowY: 'auto' }}>
                    {results.map(u => (
                        <div key={u._id} onClick={() => onStart(u)}
                            style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', cursor: 'pointer', transition: 'background 150ms' }}
                            onMouseEnter={e => e.currentTarget.style.background = 'var(--hover)'}
                            onMouseLeave={e => e.currentTarget.style.background = ''}>
                            <img src={u.avatarUrl || `https://ui-avatars.com/api/?name=${u.username}&background=6366F1&color=fff`}
                                style={{ width: 44, height: 44, borderRadius: '50%', objectFit: 'cover' }} alt="" />
                            <div>
                                <div style={{ fontWeight: 600, fontSize: 14, display: 'flex', alignItems: 'center', gap: 4 }}>
                                    {u.username} {u.isVerified && <HiBadgeCheck style={{ color: 'var(--accent)', fontSize: 13 }} />}
                                </div>
                                <div style={{ fontSize: 13, color: 'var(--text-3)' }}>{u.fullName}</div>
                            </div>
                        </div>
                    ))}
                    {q.length >= 2 && !results.length && !loading && (
                        <p style={{ textAlign: 'center', padding: '32px 0', color: 'var(--text-3)', fontSize: 14 }}>No accounts found.</p>
                    )}
                    {q.length < 2 && (
                        <p style={{ textAlign: 'center', padding: '32px 0', color: 'var(--text-3)', fontSize: 14 }}>Search for people</p>
                    )}
                </div>
            </div>
        </div>
    )
}

/* ΓöÇΓöÇ Main ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
export default function Messages() {
    const { id: paramConvoId } = useParams()
    const { user } = useAuth()
    const navigate = useNavigate()
    const [conversations, setConversations] = useState([])
    const [activeConvo, setActiveConvo] = useState(null)
    const [messages, setMessages] = useState([])
    const [loadingMessages, setLoadingMessages] = useState(false)
    const [text, setText] = useState('')
    const [peerTyping, setPeerTyping] = useState(false)
    const [showNewConvo, setShowNewConvo] = useState(false)
    const [starting, setStarting] = useState(false)
    const [mobilePanel, setMobilePanel] = useState('list')
    const [showEmoji, setShowEmoji] = useState(false)
    const [initialLoad, setInitialLoad] = useState(true)
    const [convoSearch, setConvoSearch] = useState('')
    const [filePreview, setFilePreview] = useState(null)
    const [isUploading, setIsUploading] = useState(false)
    const [editingMessageId, setEditingMessageId] = useState(null)
    const [editBody, setEditBody] = useState('')
    const [hoveredMessageId, setHoveredMessageId] = useState(null)
    const [tappedMessageId, setTappedMessageId] = useState(null)
    const fileRef = useRef()
    const docRef = useRef()
    const bottomRef = useRef()
    const typingTimer = useRef()
    const inputRef = useRef()
    const userRef = useRef(user)
    useEffect(() => { userRef.current = user }, [user])

    const insertEmoji = (emojiObj) => {
        setText(t => t + emojiObj.emoji)
        // Kept open for multiple emojis
        inputRef.current?.focus()
    }

    /* socket */

    useEffect(() => {
        const token = localStorage.getItem('accessToken')
        socket = io(SOCKET_URL, { auth: { token }, path: '/socket.io', transports: ['websocket', 'polling'] })
        socket.on('new_message', (msg) => {
            const senderId = msg.sender?._id || msg.sender
            if (senderId === userRef.current?._id) return
            
            setMessages(m => {
                // If this message belongs to the currently open conversation
                if (activeConvoRef.current?._id === msg.conversationId) {
                    // Mark as read immediately on the server
                    api.patch(`conversations/${msg.conversationId}/messages/read`, {}, { baseURL: CHAT_BASE_URL }).catch(() => {})
                    // Assume it's read locally since we are looking at it
                    msg.isRead = true
                }
                if (m.find(x => x._id === msg._id)) return m
                return [...m, msg]
            })
            setConversations(cs => cs.map(c => c._id === msg.conversationId ? { ...c, lastMessage: msg } : c))
        })
        socket.on('messages_read', ({ conversationId, readBy }) => {
            if (activeConvoRef.current?._id === conversationId && readBy !== userRef.current?._id) {
                setMessages(m => m.map(msg => msg.sender === userRef.current?._id ? { ...msg, isRead: true } : msg))
            }
        })
        socket.on('message_edited', (msg) => {
            setMessages(m => m.map(x => x._id === msg._id ? msg : x))
            setConversations(cs => cs.map(c => 
                (c.lastMessage?._id === msg._id || c._id === msg.conversation) 
                ? { ...c, lastMessage: msg } : c
            ))
        })
        socket.on('message_deleted', ({ messageId }) => {
            setMessages(m => m.filter(x => x._id !== messageId))
            // We do not re-fetch the entire conversation's lastMessage here yet, 
            // but the next refresh will auto-correct it if the last message was deleted.
        })
        socket.on('user_typing', () => setPeerTyping(true))
        socket.on('user_stop_typing', () => setPeerTyping(false))
        return () => { socket?.disconnect(); socket = null }
    }, [])

    const activeConvoRef = useRef(activeConvo)
    useEffect(() => { activeConvoRef.current = activeConvo }, [activeConvo])

    const loadConvos = async () => {
        try {
            const { data } = await api.get(`conversations`, { baseURL: CHAT_BASE_URL })
            const convos = data.data || []; setConversations(convos); return convos
        } finally {
            setInitialLoad(false)
        }
    }

    useEffect(() => {
        loadConvos().then(convos => {
            if (paramConvoId) { const f = convos.find(c => c._id === paramConvoId); if (f) selectConvo(f) }
        }).catch(() => { setInitialLoad(false) })
    }, []) // eslint-disable-line

    const selectConvo = async (convo) => {
        if (activeConvo?._id === convo._id) { setMobilePanel('chat'); return }
        if (activeConvo) socket?.emit('leave_conversation', activeConvo._id)
        setActiveConvo(convo); setMessages([]); setMobilePanel('chat'); setLoadingMessages(true)
        socket?.emit('join_conversation', convo._id)
        navigate(`/messages/${convo._id}`, { replace: true })
        try {
            const { data } = await api.get(`conversations/${convo._id}/messages`, { params: { limit: 50 }, baseURL: CHAT_BASE_URL })
            setMessages(data.data || [])
            // Mark messages as read on open
            api.patch(`conversations/${convo._id}/messages/read`, {}, { baseURL: CHAT_BASE_URL }).catch(() => {})
        } catch {
            toast.error('Failed to load messages')
        } finally {
            setLoadingMessages(false)
            setTimeout(() => inputRef.current?.focus(), 200)
        }
    }

    const startConvoWith = async (u) => {
        setShowNewConvo(false); setStarting(true)
        try {
            const { data } = await api.post(`conversations`, { targetUserId: u._id }, { baseURL: CHAT_BASE_URL })
            const fresh = await loadConvos()
            const found = fresh.find(c => c._id === data.data._id) || { ...data.data, participants: [user, u] }
            await selectConvo(found)
        } catch (err) { toast.error(err.response?.data?.message || 'Failed') }
        finally { setStarting(false) }
    }

    useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: 'smooth' }) }, [messages, peerTyping])

    const handleSend = async (e) => {
        e?.preventDefault()
        if ((!text.trim() && !filePreview) || !activeConvo) return
        if (isUploading) return

        const body = text.trim()
        const attachedFile = filePreview?.file

        setText('')
        setFilePreview(null)
        setIsUploading(true)

        clearTimeout(typingTimer.current)
        socket?.emit('stop_typing', { conversationId: activeConvo._id })

        try {
            const formData = new FormData()
            if (body) formData.append('body', body)
            if (attachedFile) formData.append('media', attachedFile)

            const { data } = await api.post(`conversations/${activeConvo._id}/messages`, formData, {
                baseURL: CHAT_BASE_URL
            })
            setMessages(m => {
                if (m.find(x => x._id === data.data._id)) return m
                return [...m, data.data]
            })
            setConversations(cs => cs.map(c => c._id === activeConvo._id ? { ...c, lastMessage: data.data } : c))
        } catch {
            toast.error('Failed to send')
            setText(body)
            if (attachedFile) setFilePreview(filePreview)
        } finally {
            setIsUploading(false)
        }
    }

    const handleFileSelect = (e) => {
        const file = e.target.files[0]
        if (!file) return

        // 50MB limit
        if (file.size > 50 * 1024 * 1024) {
            toast.error('File too large (max 50MB)')
            return
        }

        const type = file.type.startsWith('image/') ? 'image'
            : file.type.startsWith('video/') ? 'video'
                : 'doc'

        setFilePreview({
            file,
            type,
            url: type !== 'doc' ? URL.createObjectURL(file) : null,
            name: file.name
        })
        e.target.value = '' // reset
        inputRef.current?.focus()
    }

    const handleType = (e) => {
        setText(e.target.value)
        if (activeConvo) {
            socket?.emit('typing', { conversationId: activeConvo._id })
            clearTimeout(typingTimer.current)
            typingTimer.current = setTimeout(() => socket?.emit('stop_typing', { conversationId: activeConvo._id }), 2000)
        }
    }

    const startEditing = (m) => {
        setEditingMessageId(m._id)
        setEditBody(m.body || '')
    }

    const cancelEditing = () => {
        setEditingMessageId(null)
        setEditBody('')
    }

    const saveEdit = async (m) => {
        if (!editBody.trim()) return
        try {
            const { data } = await api.put(`conversations/${activeConvo._id}/messages/${m._id}`, { body: editBody }, { baseURL: CHAT_BASE_URL })
            setMessages(ms => ms.map(x => x._id === m._id ? data.data : x))
            setConversations(cs => cs.map(c => c.lastMessage?._id === m._id ? { ...c, lastMessage: data.data } : c))
            setEditingMessageId(null)
            setEditBody('')
        } catch {
            toast.error('Failed to edit message')
        }
    }

    const deleteMessage = async (m) => {
        if (!window.confirm("Delete this message for everyone?")) return
        try {
            await api.delete(`conversations/${activeConvo._id}/messages/${m._id}`, { baseURL: CHAT_BASE_URL })
            setMessages(ms => ms.filter(x => x._id !== m._id))
            toast.success('Message deleted')
        } catch {
            toast.error('Failed to delete message')
        }
    }

    const getOther = (c) => c.participants?.find(p => p._id !== user?._id)
    const other = activeConvo ? getOther(activeConvo) : null
    const otherAvatar = other?.avatarUrl || (other ? `https://ui-avatars.com/api/?name=${other.username}&background=6366F1&color=fff` : null)

    const filteredConvos = conversations.filter(c => {
        if (!convoSearch.trim()) return true
        const peer = getOther(c)
        if (!peer) return false
        const s = convoSearch.toLowerCase()
        return peer.username?.toLowerCase().includes(s) || peer.fullName?.toLowerCase().includes(s)
    })

    return (
        <>
            {/* Full-screen fixed DM overlay, starts right of the sidebar */}
            <div className="dm-wrapper" style={{
                position: 'fixed', top: 0, right: 0, bottom: 0,
                left: 'var(--sidebar-w, 240px)',
                display: 'flex', background: 'var(--bg)', zIndex: 20,
            }}>

                {/* ΓöÇΓöÇΓöÇ LEFT: conversation list ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                <div className={`dm-panel dm-list-panel${mobilePanel === 'chat' ? ' dm-mobile-hidden' : ''}`}
                    style={{ flexShrink: 0, borderRight: '1px solid var(--border)', display: 'flex', flexDirection: 'column', background: 'var(--surface)' }}>

                    {/* List header */}
                    <div style={{ padding: '20px 20px 14px', borderBottom: '1px solid var(--border)', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0 }}>
                        <div>
                            <span style={{ fontFamily: "'Syne','Inter',sans-serif", fontWeight: 800, fontSize: 20 }}>
                                {user?.username}
                            </span>
                        </div>
                        <button onClick={() => setShowNewConvo(true)}
                            style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-1)', fontSize: 22, display: 'flex', alignItems: 'center', padding: 4 }}>
                            <HiPencilAlt />
                        </button>
                    </div>

                    {/* Messages label */}
                    <div style={{ padding: '14px 20px 8px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                        <span style={{ fontWeight: 700, fontSize: 15 }}>Messages</span>
                    </div>

                    {/* Search */}
                    <div style={{ padding: '0 16px 10px', flexShrink: 0 }}>
                        <div style={{
                            display: 'flex', alignItems: 'center', gap: 8,
                            background: 'var(--hover)', borderRadius: 10, padding: '9px 14px',
                        }}>
                            <HiSearch style={{ color: 'var(--text-3)', fontSize: 15, flexShrink: 0 }} />
                            <input
                                value={convoSearch}
                                onChange={e => setConvoSearch(e.target.value)}
                                placeholder="Search"
                                style={{
                                    background: 'none', border: 'none', outline: 'none',
                                    fontSize: 14, color: 'var(--text-1)', width: '100%'
                                }}
                            />
                        </div>
                    </div>

                    {/* Convo items */}
                    <div style={{ flex: 1, overflowY: 'auto' }}>
                        {initialLoad ? (
                            <div style={{ padding: '10px 16px' }}>
                                {Array.from({ length: Math.floor(window.innerHeight / 72) || 8 }).map((_, i) => (
                                    <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 14, padding: '10px 0', opacity: 1 - i * 0.1 }}>
                                        <div className="skeleton-media" style={{ width: 52, height: 52, borderRadius: '50%', flexShrink: 0 }} />
                                        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 6 }}>
                                            <div className="skeleton-text" style={{ width: '40%', height: 14, borderRadius: 4 }} />
                                            <div className="skeleton-text" style={{ width: '70%', height: 12, borderRadius: 4 }} />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        ) : starting ? (
                            <div style={{ display: 'flex', justifyContent: 'center', padding: 20 }}><div className="spinner" /></div>
                        ) : null}
                        
                        {!initialLoad && filteredConvos.map(c => {
                            const peer = getOther(c)
                            const pav = peer?.avatarUrl || `https://ui-avatars.com/api/?name=${peer?.username}&background=6366F1&color=fff`
                            const isActive = activeConvo?._id === c._id
                            return (
                                <div key={c._id} onClick={() => selectConvo(c)}
                                    style={{
                                        display: 'flex', alignItems: 'center', gap: 14,
                                        padding: '10px 16px', cursor: 'pointer',
                                        background: isActive ? 'var(--hover)' : 'transparent',
                                        transition: 'background 120ms',
                                    }}
                                    onMouseEnter={e => { if (!isActive) e.currentTarget.style.background = 'var(--hover)' }}
                                    onMouseLeave={e => { if (!isActive) e.currentTarget.style.background = 'transparent' }}>
                                    <div style={{ position: 'relative', flexShrink: 0 }}>
                                        <img src={pav} style={{ width: 52, height: 52, borderRadius: '50%', objectFit: 'cover', display: 'block' }} alt="" />
                                        <div style={{ position: 'absolute', bottom: 1, right: 1, width: 13, height: 13, background: 'var(--success)', borderRadius: '50%', border: '2.5px solid var(--surface)' }} />
                                    </div>
                                    <div style={{ flex: 1, minWidth: 0 }}>
                                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 2 }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: 4, fontWeight: 600, fontSize: 14 }}>
                                                {peer?.username}
                                                {peer?.isVerified && <HiBadgeCheck style={{ color: 'var(--accent)', fontSize: 13 }} />}
                                            </div>
                                            {c.lastMessage?.createdAt && (
                                                <span style={{ fontSize: 11, color: 'var(--text-3)', flexShrink: 0 }}>{timeago(c.lastMessage.createdAt)}</span>
                                            )}
                                        </div>
                                        <div style={{ fontSize: 13, color: 'var(--text-3)', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                            {c.lastMessage?.body || 'Say hi ≡ƒæï'}
                                        </div>
                                    </div>
                                </div>
                            )
                        })}
                        {!initialLoad && !conversations.length && !starting && (
                            <div style={{ textAlign: 'center', padding: '60px 20px', color: 'var(--text-3)' }}>
                                <div style={{ fontSize: 44, marginBottom: 14 }}>Γ£ë∩╕Å</div>
                                <p style={{ fontWeight: 700, fontSize: 15, color: 'var(--text-1)', marginBottom: 8 }}>Your messages</p>
                                <p style={{ fontSize: 13, marginBottom: 20 }}>Send a message to start a conversation</p>
                                <button className="btn btn-primary btn-sm" onClick={() => setShowNewConvo(true)}>Send message</button>
                            </div>
                        )}
                    </div>
                </div>

                {/* ΓöÇΓöÇΓöÇ RIGHT: chat area ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                <div className={`dm-panel dm-chat-panel${mobilePanel === 'list' ? ' dm-mobile-hidden' : ''}`}
                    style={{ flex: 1, display: 'flex', flexDirection: 'column', minWidth: 0, background: 'var(--bg)' }}>

                    {activeConvo && other ? (
                        <>
                            {/* Chat header */}
                            <div style={{
                                display: 'flex', alignItems: 'center', gap: 12,
                                padding: '12px 20px', borderBottom: '1px solid var(--border)',
                                background: 'var(--surface)', flexShrink: 0,
                            }}>
                                <button className="dm-back-btn btn btn-ghost btn-icon" onClick={() => { setMobilePanel('list'); navigate('/messages', { replace: true }) }}>
                                    <HiArrowLeft />
                                </button>
                                <div style={{ position: 'relative' }}>
                                    <img src={otherAvatar} style={{ width: 40, height: 40, borderRadius: '50%', objectFit: 'cover', display: 'block' }} alt="" />
                                    <div style={{ position: 'absolute', bottom: 0, right: 0, width: 11, height: 11, background: 'var(--success)', borderRadius: '50%', border: '2px solid var(--surface)' }} />
                                </div>
                                <div style={{ flex: 1 }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 5, fontWeight: 700, fontSize: 14 }}>
                                        {other.username}
                                        {other.isVerified && <HiBadgeCheck style={{ color: 'var(--accent)', fontSize: 13 }} />}
                                    </div>
                                    <div style={{ fontSize: 12, color: peerTyping ? 'var(--accent)' : 'var(--success)', marginTop: 1 }}>
                                        {peerTyping ? 'typingΓÇª' : 'ΓùÅ Active now'}
                                    </div>
                                </div>
                            </div>

                            {/* Messages */}
                            <div style={{ flex: 1, overflowY: 'auto', padding: '20px 16px', display: 'flex', flexDirection: 'column', gap: 2 }}>
                                {loadingMessages ? (
                                    <>
                                        {Array.from({ length: 5 }).map((_, i) => <MessageSkeleton key={i} />)}
                                    </>
                                ) : messages.length === 0 && (
                                    <div style={{ textAlign: 'center', margin: 'auto', color: 'var(--text-3)' }}>
                                        <img src={otherAvatar} style={{ width: 80, height: 80, borderRadius: '50%', objectFit: 'cover', margin: '0 auto 14px', display: 'block' }} alt="" />
                                        <p style={{ fontWeight: 700, fontSize: 16, color: 'var(--text-1)', marginBottom: 4 }}>{other.username}</p>
                                        <p style={{ fontSize: 13 }}>Send a message to start the conversation</p>
                                    </div>
                                )}

                                {!loadingMessages && messages.map((m, i) => {
                                    const isMine = m.sender === user?._id || m.sender?._id === user?._id
                                    const nextSender = messages[i + 1]?.sender?._id || messages[i + 1]?.sender
                                    const prevSender = messages[i - 1]?.sender?._id || messages[i - 1]?.sender
                                    const curSender = m.sender?._id || m.sender
                                    const isFirst = prevSender !== curSender
                                    const isLast = nextSender !== curSender

                                    const r = 20
                                    const rSmall = 4
                                    const borderRadius = isMine
                                        ? `${r}px ${isFirst ? r : rSmall}px ${isLast ? r : rSmall}px ${r}px`
                                        : `${isFirst ? r : rSmall}px ${r}px ${r}px ${isLast ? r : rSmall}px`

                                    return (
                                        <div key={m._id || i} style={{
                                            display: 'flex', flexDirection: 'column',
                                            alignItems: isMine ? 'flex-end' : 'flex-start',
                                            marginBottom: isLast ? 6 : 1,
                                            position: 'relative'
                                        }}
                                        onMouseEnter={() => setHoveredMessageId(m._id)}
                                        onMouseLeave={() => setHoveredMessageId(null)}
                                        onTouchStart={() => { if (isMine) setTappedMessageId(id => id === m._id ? null : m._id) }}>

                                            {/* (Edit/Delete moved below message) */}

                                            {/* Avatar for theirs, first in group */}
                                            {!isMine && isFirst && (
                                                <img src={otherAvatar}
                                                    style={{ width: 28, height: 28, borderRadius: '50%', objectFit: 'cover', marginBottom: 2, display: 'block' }}
                                                    alt="" />
                                            )}

                                            <div style={{
                                                maxWidth: '65%',
                                                padding: '10px 14px',
                                                borderRadius,
                                                background: isMine ? 'var(--accent)' : 'var(--dm-theirs)',
                                                color: isMine ? '#fff' : 'var(--text-1)',
                                                fontSize: 14.5, lineHeight: 1.5,
