                                            <div style={{ display: 'flex', alignItems: 'center', gap: 10, marginTop: 4, paddingInline: 2 }}>
                                                {isMine && !editingMessageId && Date.now() - new Date(m.createdAt).getTime() <= 15 * 60 * 1000 && (
                                                    <div style={{ display: 'flex', gap: 6, opacity: 0.7 }}>
