                                        <button type="submit" style={{
                                            background: (text.trim() || filePreview) ? 'var(--accent)' : 'var(--hover)',
                                            border: 'none', borderRadius: '50%',
                                            width: 38, height: 38,
                                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                                            cursor: 'pointer',
                                            color: (text.trim() || filePreview) ? '#fff' : 'var(--text-3)',
                                            flexShrink: 0,
                                            transition: 'all 0.2s',
                                            fontSize: 18,
                                        }}>
                                            <HiPaperAirplane style={{ transform: 'rotate(90deg)' }} />
                                        </button>
                                    )}
                                </form>
                            </div>
                        </>
                    ) : (
                        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: 'var(--text-3)', textAlign: 'center', padding: 32, gap: 16 }}>
                            <div style={{
                                width: 80, height: 80, borderRadius: '50%',
                                border: '2px solid var(--text-2)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                fontSize: 32,
                            }}>Γ£ë∩╕Å</div>
                            <div>
                                <p style={{ fontSize: 20, fontWeight: 700, color: 'var(--text-1)', marginBottom: 8 }}>Your messages</p>
                                <p style={{ fontSize: 14, marginBottom: 20 }}>Send private photos and messages to a friend or group</p>
                                <button className="btn btn-primary" onClick={() => setShowNewConvo(true)}>
                                    Send message
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* Spacer behind the fixed panel */}
            <div style={{ height: '100dvh' }} />

            {showNewConvo && <NewConvoModal onClose={() => setShowNewConvo(false)} onStart={startConvoWith} />}
        </>
    )
}

import { useState, useEffect, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import api, { SOCKET_URL } from '../api/axios'
import { Link } from 'react-router-dom'
import { timeago } from '../utils/timeago'
import { io } from 'socket.io-client'
import { useAuth } from '../context/AuthContext'
import {
    HiBell, HiHeart, HiChatAlt2, HiUserAdd, HiCheck, HiBadgeCheck, HiAtSymbol
} from 'react-icons/hi'

/* ΓöÇΓöÇ type config ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
const typeConfig = {
    like: {
        icon: HiHeart,
        gradient: 'linear-gradient(135deg,#FF375F,#FF9500)',
        text: 'liked your post',
        emoji: 'Γ¥ñ∩╕Å',
    },
    comment: {
        icon: HiChatAlt2,
        gradient: 'linear-gradient(135deg,#6366F1,#A78BFA)',
        text: 'commented on your post',
        emoji: '≡ƒÆ¼',
    },
    follow: {
        icon: HiUserAdd,
        gradient: 'linear-gradient(135deg,#10B981,#06C8FF)',
        text: 'started following you',
        emoji: '≡ƒæñ',
    },
    mention: {
        icon: HiAtSymbol,
        gradient: 'linear-gradient(135deg,#F59E0B,#EF4444)',
        text: 'mentioned you',
        emoji: '≡ƒôú',
    },
}

/* ΓöÇΓöÇ Group notifications by time ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function groupByTime(notifs) {
    const now = Date.now()
    const DAY = 86400000
    const WEEK = DAY * 7
    const groups = { today: [], thisWeek: [], earlier: [] }
    for (const n of notifs) {
        const diff = now - new Date(n.createdAt).getTime()
        if (diff < DAY) groups.today.push(n)
        else if (diff < WEEK) groups.thisWeek.push(n)
        else groups.earlier.push(n)
    }
    return groups
}

/* ΓöÇΓöÇ Single notification row ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
function NotifRow({ n, index, onFollowBack }) {
    const cfg = typeConfig[n.type] || typeConfig.like
    const Icon = cfg.icon
    const avatar = n.sender?.avatarUrl ||
        `https://ui-avatars.com/api/?name=${n.sender?.username}&background=6366F1&color=fff`
    const [followed, setFollowed] = useState(false)

    const handleFollowBack = async (e) => {
        e.preventDefault()
        e.stopPropagation()
        setFollowed(true)
        try {
            await api.post(`/users/${n.sender?._id}/follow`)
            onFollowBack?.()
        } catch {
            setFollowed(false)
        }
    }

    return (
        <motion.div
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.03, duration: 0.2, ease: [0.4, 0, 0.2, 1] }}
            style={{
                display: 'flex', alignItems: 'center', gap: 12,
                padding: '12px 16px',
                background: n.isRead ? 'transparent' : 'rgba(99,102,241,0.06)',
                borderRadius: 12,
                transition: 'background 0.2s',
                cursor: 'default',
            }}
            whileHover={{ background: 'var(--hover)' }}
        >
            {/* Avatar + icon badge */}
            <Link to={`/profile/${n.sender?._id}`} style={{ position: 'relative', flexShrink: 0 }}>
                <img
                    src={avatar}
                    alt={n.sender?.username}
                    style={{
                        width: 46, height: 46, borderRadius: '50%',
                        objectFit: 'cover', display: 'block',
                        border: '2px solid var(--border)',
                    }}
                />
                {/* Icon badge bottom-right */}
                <div style={{
                    position: 'absolute', bottom: -2, right: -2,
                    width: 20, height: 20, borderRadius: '50%',
                    background: cfg.gradient,
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    border: '2px solid var(--bg)',
                    boxShadow: '0 2px 6px rgba(0,0,0,0.25)',
                }}>
                    <Icon style={{ color: '#fff', fontSize: 10 }} />
                </div>
            </Link>

            {/* Text */}
            <div style={{ flex: 1, minWidth: 0 }}>
                <p style={{ fontSize: 14, lineHeight: 1.4, margin: 0, color: 'var(--text-1)' }}>
                    <Link
                        to={`/profile/${n.sender?._id}`}
                        style={{ fontWeight: 700, color: 'var(--text-1)', textDecoration: 'none' }}
                    >
                        {n.sender?.username}
                    </Link>
                    {n.sender?.isVerified && (
                        <HiBadgeCheck style={{ color: 'var(--accent)', fontSize: 13, marginLeft: 3, verticalAlign: 'middle' }} />
                    )}
                    <span style={{ fontWeight: 400, color: 'var(--text-2)', marginLeft: 4 }}>{cfg.text}</span>
                </p>
                <p style={{ fontSize: 12, color: 'var(--text-3)', margin: '3px 0 0', lineHeight: 1 }}>
                    {timeago(n.createdAt)}
                </p>
            </div>

            {/* Right action ΓÇö thumbnail for posts, follow-back for follows */}
            <div style={{ flexShrink: 0 }}>
                {n.type === 'follow' ? (
                    !followed ? (
                        <motion.button
                            onClick={handleFollowBack}
                            style={{
                                background: 'var(--accent)',
                                color: '#fff', border: 'none',
                                borderRadius: 8, padding: '7px 16px',
                                fontSize: 13, fontWeight: 700,
                                cursor: 'pointer',
                            }}
                            whileHover={{ scale: 1.04 }}
                            whileTap={{ scale: 0.96 }}
                        >
                            Follow
                        </motion.button>
                    ) : (
                        <span style={{
                            background: 'var(--hover)', color: 'var(--text-2)',
                            border: '1px solid var(--border-md)',
                            borderRadius: 8, padding: '7px 14px',
                            fontSize: 13, fontWeight: 600,
                            display: 'inline-block',
                        }}>
                            Following
                        </span>
                    )
                ) : n.post?.mediaUrl ? (
                    <Link to={n.post?._id ? `/posts/${n.post._id}` : '#'}>
                        <img
                            src={n.post.mediaUrl}
                            alt=""
                            style={{
                                width: 44, height: 44, borderRadius: 8,
                                objectFit: 'cover', display: 'block',
                                border: '1px solid var(--border)',
                            }}
                        />
                    </Link>
                ) : null}
            </div>
        </motion.div>
    )
}

/* ΓöÇΓöÇ Section header ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
