}

/* ΓöÇΓöÇ Main component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */
export default function Notifications() {
    const { user } = useAuth()
    const [notifs, setNotifs] = useState([])
    const [unread, setUnread] = useState(0)
    const [loading, setLoading] = useState(true)
    const [hasNew, setHasNew] = useState(false)
    const socketRef = useRef(null)

    const load = async () => {
        try {
            const { data } = await api.get('/notifications')
            setNotifs(data.data || [])
            setUnread(data.unreadCount || 0)
        } catch { /* silent */ }
        finally { setLoading(false) }
    }

    useEffect(() => {
        load()

        // Real-time: subscribe to new_notification events
        const token = localStorage.getItem('accessToken')
        if (token) {
            socketRef.current = io(SOCKET_URL, {
                auth: { token },
                path: '/socket.io',
                transports: ['websocket', 'polling'],
            })
            socketRef.current.on('new_notification', (notif) => {
                setNotifs(prev => [{ ...notif, isRead: false }, ...prev])
                setUnread(u => u + 1)
                setHasNew(true)
            })
        }

        return () => {
            socketRef.current?.disconnect()
            socketRef.current = null
        }
    }, [])

    const markRead = async () => {
        await api.patch('/notifications/read').catch(() => { })
        setUnread(0)
        setNotifs(n => n.map(x => ({ ...x, isRead: true })))
        setHasNew(false)
    }

    // Auto-mark read when page opens after 1.5 seconds
    useEffect(() => {
        const t = setTimeout(() => {
            if (unread > 0) markRead()
        }, 1500)
        return () => clearTimeout(t)
    }, [unread])

    const groups = groupByTime(notifs)

    return (
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.2 }}
            style={{ maxWidth: 600, margin: '0 auto', paddingBottom: 40 }}
        >
            {/* ΓöÇΓöÇ Header ΓöÇΓöÇ */}
            <div style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                padding: '20px 16px 12px',
                position: 'sticky', top: 0, zIndex: 10,
                background: 'var(--bg)',
                borderBottom: '1px solid var(--border)',
                backdropFilter: 'blur(12px)',
            }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <div style={{
                        width: 38, height: 38, borderRadius: '50%',
                        background: 'linear-gradient(135deg,#6366F1,#A78BFA)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        boxShadow: '0 4px 12px rgba(99,102,241,0.4)',
                    }}>
                        <HiBell style={{ color: '#fff', fontSize: 20 }} />
                    </div>
                    <div>
                        <h1 style={{ fontSize: 20, fontWeight: 800, margin: 0, lineHeight: 1.1 }}>
                            Notifications
                        </h1>
                        {unread > 0 && (
                            <p style={{ fontSize: 12, color: 'var(--accent)', margin: 0, fontWeight: 600 }}>
                                {unread} new
                            </p>
                        )}
                    </div>
                </div>

                {unread > 0 && (
                    <motion.button
                        onClick={markRead}
                        style={{
                            display: 'flex', alignItems: 'center', gap: 6,
                            background: 'var(--hover)', border: '1px solid var(--border-md)',
                            borderRadius: 20, padding: '7px 14px',
                            fontSize: 13, fontWeight: 600, color: 'var(--text-2)',
                            cursor: 'pointer',
                        }}
                        whileHover={{ scale: 1.03, background: 'var(--border)' }}
                        whileTap={{ scale: 0.97 }}
                    >
                        <HiCheck style={{ fontSize: 14 }} />
                        Mark all read
                    </motion.button>
                )}
            </div>

            {/* ΓöÇΓöÇ New notif flash indicator ΓöÇΓöÇ */}
            <AnimatePresence>
                {hasNew && (
                    <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        style={{
                            background: 'linear-gradient(90deg, rgba(99,102,241,0.12), rgba(167,139,250,0.12))',
                            borderBottom: '1px solid rgba(99,102,241,0.2)',
                            padding: '10px 20px',
                            fontSize: 13, color: 'var(--accent)', fontWeight: 600,
                            display: 'flex', alignItems: 'center', gap: 8,
                        }}
                    >
                        <div style={{
                            width: 8, height: 8, borderRadius: '50%',
                            background: 'var(--accent)',
                            boxShadow: '0 0 6px var(--accent)',
                            animation: 'pulse 1.5s ease-in-out infinite',
                        }} />
                        New notifications arrived
                    </motion.div>
                )}
            </AnimatePresence>

            {/* ΓöÇΓöÇ Content ΓöÇΓöÇ */}
            {loading ? (
                <div style={{ padding: '8px 0' }}>
                    {[...Array(6)].map((_, i) => <NotifSkeleton key={i} />)}
                </div>
            ) : notifs.length === 0 ? (
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.1 }}
                    style={{
                        display: 'flex', flexDirection: 'column', alignItems: 'center',
                        justifyContent: 'center', padding: '80px 32px', gap: 16, textAlign: 'center',
                    }}
                >
                    <div style={{
                        width: 80, height: 80, borderRadius: '50%',
                        background: 'linear-gradient(135deg,rgba(99,102,241,0.15),rgba(167,139,250,0.15))',
                        border: '2px solid rgba(99,102,241,0.2)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: 36,
                    }}>
                        ≡ƒöö
                    </div>
                    <div>
                        <p style={{ fontSize: 18, fontWeight: 700, color: 'var(--text-1)', margin: '0 0 8px' }}>
                            All caught up
                        </p>
                        <p style={{ fontSize: 14, color: 'var(--text-3)', margin: 0, lineHeight: 1.5 }}>
                            When someone likes, comments or follows you,&lt;br /&gt;you&apos;ll see it here.
                        </p>
                    </div>
                </motion.div>
            ) : (
                <div style={{ padding: '8px 0' }}>
                    {groups.today.length > 0 && (
                        <>
                            <SectionLabel label="Today" />
                            {groups.today.map((n, i) => (
                                <NotifRow key={n._id} n={n} index={i} />
                            ))}
                        </>
                    )}
                    {groups.thisWeek.length > 0 && (
                        <>
                            <SectionLabel label="This Week" />
                            {groups.thisWeek.map((n, i) => (
                                <NotifRow key={n._id} n={n} index={groups.today.length + i} />
                            ))}
                        </>
                    )}
                    {groups.earlier.length > 0 && (
                        <>
                            <SectionLabel label="Earlier" />
                            {groups.earlier.map((n, i) => (
                                <NotifRow key={n._id} n={n} index={groups.today.length + groups.thisWeek.length + i} />
                            ))}
                        </>
                    )}
                </div>
            )}
        </motion.div>
    )
}

import { useState, useEffect, useRef } from 'react'
import { useParams, Link, useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import { motion, AnimatePresence } from 'framer-motion'
import api from '../api/axios'
import {
    HiHeart, HiOutlineHeart, HiBookmark, HiOutlineBookmark,
    HiDotsHorizontal, HiShare, HiPencil, HiTrash, HiArrowLeft,
    HiBadgeCheck, HiEmojiHappy,
} from 'react-icons/hi'
import toast from 'react-hot-toast'
import { timeago } from '../utils/timeago'
import EditPostModal from '../components/EditPostModal'

export default function PostDetail() {
    const { id } = useParams()
    const { user } = useAuth()
    const navigate = useNavigate()
    const [post, setPost] = useState(null)
    const [comments, setComments] = useState([])
    const [body, setBody] = useState('')
    const [liked, setLiked] = useState(false)
    const [likesCount, setLikesCount] = useState(0)
    const [saved, setSaved] = useState(false)
    const [loading, setLoading] = useState(true)
    const [menuOpen, setMenuOpen] = useState(false)
    const [editOpen, setEditOpen] = useState(false)
    const [replyingTo, setReplyingTo] = useState(null)
    const [replyData, setReplyData] = useState({}) // { commentId: { replies: [], loading: false, show: false } }
    const inputRef = useRef()
    const menuRef = useRef()
    const commentsEndRef = useRef()

    useEffect(() => {
        Promise.all([
            api.get(`/posts/${id}`),
            api.get(`/posts/${id}/comments`, { params: { limit: 50 } }),
        ]).then(([{ data: pd }, { data: cd }]) => {
            setPost(pd.data)
            setLiked(pd.data.isLiked || false)
            setLikesCount(pd.data.likesCount || 0)
            setSaved(pd.data.isSaved || false)
            setComments(cd.data || [])
        }).catch(() => toast.error('Post not found'))
            .finally(() => setLoading(false))
    }, [id])

    // Close menu on outside click
    useEffect(() => {
        if (!menuOpen) return
        const h = (e) => { if (menuRef.current && !menuRef.current.contains(e.target)) setMenuOpen(false) }
        document.addEventListener('mousedown', h)
        return () => document.removeEventListener('mousedown', h)
    }, [menuOpen])

    const handleLike = async () => {
        if (!user) { toast.error('Please sign in to like posts'); return navigate('/login'); }
        const next = !liked; setLiked(next); setLikesCount(c => next ? c + 1 : c - 1)
        try { next ? await api.post(`/posts/${id}/like`) : await api.delete(`/posts/${id}/like`) }
        catch { setLiked(!next); setLikesCount(c => next ? c - 1 : c + 1) }
    }

    const handleSave = async () => {
        if (!user) { toast.error('Please sign in to save posts'); return navigate('/login'); }
        const next = !saved; setSaved(next)
        try { next ? await api.post(`/posts/${id}/save`) : await api.delete(`/posts/${id}/save`) }
        catch { setSaved(!next) }
    }

    const handleShare = () => {
        const url = `${window.location.origin}/posts/${id}`
        if (navigator.share) navigator.share({ title: 'PeerNet post', url })
        else navigator.clipboard.writeText(url).then(() => toast.success('Link copied!'))
    }

    const handleDelete = async () => {
        if (!confirm('Delete this post?')) return
        try { await api.delete(`/posts/${id}`); toast.success('Post deleted'); navigate(-1) }
        catch { toast.error('Delete failed') }
    }

    const handleComment = async (e) => {
        e.preventDefault()
        if (!user) { toast.error('Please sign in to comment'); return navigate('/login'); }
        if (!body.trim()) return
        try {
            const payload = { body }
            if (replyingTo) payload.parentComment = replyingTo._id

            const { data } = await api.post(`/posts/${id}/comments`, payload)

            if (replyingTo) {
                // Add to replies of the parent comment
                setReplyData(prev => ({
                    ...prev,
                    [replyingTo._id]: {
                        ...prev[replyingTo._id],
                        replies: [...(prev[replyingTo._id]?.replies || []), data.data],
                        show: true
                    }
                }))
            } else {
                // Add to top level comments
                setComments(c => [...c, data.data])
                setTimeout(() => commentsEndRef.current?.scrollIntoView({ behavior: 'smooth' }), 100)
            }
            
            setBody('')
            setReplyingTo(null)
        } catch (err) { toast.error(err.response?.data?.message || 'Failed') }
    }

    const toggleReplies = async (commentId) => {
        const current = replyData[commentId]
        
        // If we already have them and are showing them, hide them
        if (current?.show) {
            setReplyData(prev => ({ ...prev, [commentId]: { ...prev[commentId], show: false } }))
            return
        }

        // If we already have them but they're hidden, just show them
        if (current?.replies) {
            setReplyData(prev => ({ ...prev, [commentId]: { ...prev[commentId], show: true } }))
            return
        }

        // Otherwise fetch them
        setReplyData(prev => ({ ...prev, [commentId]: { loading: true, show: true, replies: [] } }))
        try {
            const { data } = await api.get(`/posts/${id}/comments/${commentId}/replies`)
            setReplyData(prev => ({
                ...prev,
                [commentId]: { loading: false, show: true, replies: data.data || [] }
            }))
        } catch (err) {
            setReplyData(prev => ({ ...prev, [commentId]: { loading: false, show: false, replies: [] } }))
            toast.error('Failed to load replies')
        }
    }

    if (loading) return <div style={{ display: 'flex', justifyContent: 'center', padding: 80 }}><div className="spinner" /></div>
    if (!post) return null

    const author = post.author || {}
    const avatar = author.avatarUrl || `https://ui-avatars.com/api/?name=${author.username}&background=6366F1&color=fff`
    const isOwner = user?._id === (author._id || author)

    return (
        <>
            {/* Back header */}
            <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 16 }}>
                <button onClick={() => navigate(-1)} className="btn btn-ghost btn-icon"><HiArrowLeft /></button>
                <span style={{ fontWeight: 700, fontSize: 17 }}>Post</span>
            </div>

            {/* Instagram split-view card */}
            <div className="post-detail-card">

                {/* ΓöÇΓöÇ LEFT: media ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                <div className="post-detail-media">
                    {post.mediaType === 'video'
                        ? <video src={post.mediaUrl} controls style={{ width: '100%', height: '100%', objectFit: 'contain' }} />
                        : <img src={post.mediaUrl} alt={post.caption} style={{ width: '100%', height: '100%', objectFit: 'contain', display: 'block' }} />
                    }
                </div>

                {/* ΓöÇΓöÇ RIGHT: info + comments ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
                <div className="post-detail-info">

                    {/* Header */}
                    <div style={{
                        display: 'flex', alignItems: 'center', gap: 12, padding: '14px 16px',
                        borderBottom: '1px solid var(--border)', flexShrink: 0,
                    }}>
                        <Link to={`/profile/${author._id}`}>
                            <img src={avatar} style={{ width: 38, height: 38, borderRadius: '50%', objectFit: 'cover', display: 'block' }} alt="" />
                        </Link>
                        <div style={{ flex: 1 }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 4, fontWeight: 700, fontSize: 14 }}>
                                <Link to={`/profile/${author._id}`} style={{ color: 'var(--text-1)', textDecoration: 'none' }}>
                                    {author.username}
                                </Link>
                                {author.isVerified && <HiBadgeCheck style={{ color: 'var(--accent)', fontSize: 13 }} />}
                            </div>
                            <div style={{ fontSize: 12, color: 'var(--text-3)' }}>{timeago(post.createdAt)}</div>
                        </div>

                        {/* ┬╖┬╖┬╖ menu */}
                        <div style={{ position: 'relative' }} ref={menuRef}>
                            <button className="btn btn-ghost btn-icon" onClick={() => setMenuOpen(o => !o)}>
                                <HiDotsHorizontal />
                            </button>
                            <AnimatePresence>
                                {menuOpen && (
                                    <motion.div
                                        initial={{ opacity: 0, scale: 0.9, y: -6 }}
                                        animate={{ opacity: 1, scale: 1, y: 0 }}
                                        exit={{ opacity: 0, scale: 0.9, y: -6 }}
                                        transition={{ duration: 0.12 }}
                                        style={{
                                            position: 'absolute', top: '100%', right: 0, zIndex: 50,
                                            background: 'var(--surface)', border: '1px solid var(--border-md)',
                                            borderRadius: 12, boxShadow: 'var(--shadow-lg)',
                                            minWidth: 170, overflow: 'hidden',
                                        }}>
                                        <button onClick={handleShare} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-1)', fontSize: 14 }}
                                            onMouseEnter={e => e.currentTarget.style.background = 'var(--hover)'}
                                            onMouseLeave={e => e.currentTarget.style.background = 'none'}>
                                            <HiShare /> Copy link
                                        </button>
                                        {isOwner && (
                                            <>
                                                <button onClick={() => { setMenuOpen(false); setEditOpen(true) }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-1)', fontSize: 14 }}
                                                    onMouseEnter={e => e.currentTarget.style.background = 'var(--hover)'}
                                                    onMouseLeave={e => e.currentTarget.style.background = 'none'}>
                                                    <HiPencil /> Edit post
                                                </button>
                                                <button onClick={() => { setMenuOpen(false); handleDelete() }} style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', background: 'none', border: 'none', cursor: 'pointer', color: 'var(--error)', fontSize: 14 }}
                                                    onMouseEnter={e => e.currentTarget.style.background = 'var(--hover)'}
                                                    onMouseLeave={e => e.currentTarget.style.background = 'none'}>
                                                    <HiTrash /> Delete post
                                                </button>
                                            </>
                                        )}
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </div>
                    </div>

                    {/* Caption */}
                    {post.caption && (
                        <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--border)', flexShrink: 0, display: 'flex', gap: 10, alignItems: 'flex-start' }}>
                            <img src={avatar} style={{ width: 32, height: 32, borderRadius: '50%', objectFit: 'cover', flexShrink: 0, display: 'block' }} alt="" />
                            <div style={{ fontSize: 14, lineHeight: 1.5 }}>
                                <strong style={{ marginRight: 6 }}>{author.username}</strong>
                                {post.caption}
                            </div>
                        </div>
                    )}

                    {/* Comments list */}
                    <div style={{ flex: 1, overflowY: 'auto', padding: '10px 16px', display: 'flex', flexDirection: 'column', gap: 14 }}>
                        {comments.length === 0 ? (
                            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', color: 'var(--text-3)', textAlign: 'center', gap: 8 }}>
                                <span style={{ fontSize: 32 }}>≡ƒÆ¼</span>
                                <p style={{ fontWeight: 700, fontSize: 15, color: 'var(--text-1)' }}>No comments yet</p>
                                <p style={{ fontSize: 13 }}>Be the first to comment</p>
                            </div>
                        ) : (
                            comments.map(c => {
                                const cav = c.author?.avatarUrl || `https://ui-avatars.com/api/?name=${c.author?.username}&background=6366F1&color=fff`
                                return (
                                    <div key={c._id} style={{ display: 'flex', gap: 10, alignItems: 'flex-start' }}>
                                        <Link to={`/profile/${c.author?._id}`}>
                                            <img src={cav} style={{ width: 32, height: 32, borderRadius: '50%', objectFit: 'cover', flexShrink: 0, display: 'block' }} alt="" />
                                        </Link>
                                        <div style={{ flex: 1 }}>
                                            <div style={{ fontSize: 14, lineHeight: 1.5 }}>
                                                <strong style={{ marginRight: 6 }}>
                                                    <Link to={`/profile/${c.author?._id}`} style={{ color: 'var(--text-1)', textDecoration: 'none' }}>
                                                        {c.author?.username}
                                                    </Link>
                                                </strong>
                                                {c.body}
                                            </div>
                                            <div style={{ fontSize: 11, color: 'var(--text-3)', marginTop: 3, display: 'flex', gap: 12, alignItems: 'center' }}>
                                                <span>{timeago(c.createdAt)}</span>
                                                <button 
                                                    onClick={() => {
                                                        if (!user) { toast.error('Please sign in to reply'); return navigate('/login'); }
                                                        setReplyingTo(replyingTo?._id === c._id ? null : c);
                                                        if (replyingTo?._id !== c._id) setTimeout(() => inputRef.current?.focus(), 10);
                                                    }}
                                                    style={{ background: 'none', border: 'none', color: replyingTo?._id === c._id ? 'var(--text-1)' : 'var(--text-3)', fontWeight: 600, cursor: 'pointer', padding: 0 }}
                                                >
                                                    {replyingTo?._id === c._id ? 'Cancel reply' : 'Reply'}
                                                </button>
                                            </div>

                                            {/* Replies Toggle */}
                                            <div style={{ marginTop: 8 }}>
                                                <button 
                                                    onClick={() => toggleReplies(c._id)}
                                                    style={{ display: 'flex', alignItems: 'center', gap: 8, background: 'none', border: 'none', color: 'var(--text-3)', fontSize: 11, fontWeight: 600, cursor: 'pointer', padding: 0 }}
                                                >
                                                    <div style={{ width: 20, height: 1, background: 'var(--border)' }} />
                                                    {replyData[c._id]?.loading ? 'Loading...' : replyData[c._id]?.show ? 'Hide replies' : 'View replies'}
                                                </button>
                                            </div>

                                            {/* Replies List */}
                                            {replyData[c._id]?.show && (
                                                <div style={{ marginTop: 12, display: 'flex', flexDirection: 'column', gap: 12 }}>
                                                    {replyData[c._id]?.replies?.map(reply => {
                                                        const rav = reply.author?.avatarUrl || `https://ui-avatars.com/api/?name=${reply.author?.username}&background=6366F1&color=fff`
                                                        return (
                                                            <div key={reply._id} style={{ display: 'flex', gap: 10, alignItems: 'flex-start' }}>
                                                                <Link to={`/profile/${reply.author?._id}`}>
                                                                    <img src={rav} style={{ width: 24, height: 24, borderRadius: '50%', objectFit: 'cover', flexShrink: 0, display: 'block' }} alt="" />
                                                                </Link>
                                                                <div style={{ flex: 1 }}>
                                                                    <div style={{ fontSize: 13, lineHeight: 1.5 }}>
                                                                        <strong style={{ marginRight: 6 }}>
                                                                            <Link to={`/profile/${reply.author?._id}`} style={{ color: 'var(--text-1)', textDecoration: 'none' }}>
                                                                                {reply.author?.username}
                                                                            </Link>
                                                                        </strong>
                                                                        {reply.body}
                                                                    </div>
                                                                    <div style={{ fontSize: 11, color: 'var(--text-3)', marginTop: 3 }}>{timeago(reply.createdAt)}</div>
                                                                </div>
                                                            </div>
                                                        )
                                                    })}
                                                </div>
                                            )}
                                        </div>
                                    </div>
                                )
                            })
                        )}
                        <div ref={commentsEndRef} />
                    </div>

                    {/* Action bar */}
                    <div style={{ borderTop: '1px solid var(--border)', padding: '10px 16px', flexShrink: 0 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 14, marginBottom: 8 }}>
                            <motion.button className={`post-action-btn ${liked ? 'liked' : ''}`} onClick={handleLike} whileTap={{ scale: 0.85 }}>
                                {liked ? <HiHeart style={{ fontSize: 24 }} /> : <HiOutlineHeart style={{ fontSize: 24 }} />}
                            </motion.button>
                            <button className="post-action-btn" onClick={() => inputRef.current?.focus()}>
                                <HiEmojiHappy style={{ fontSize: 22 }} />
                            </button>
                            <button className="post-action-btn" onClick={handleShare}>
                                <HiShare style={{ fontSize: 22 }} />
                            </button>
                            <motion.button className={`post-action-btn ${saved ? 'saved' : ''}`} onClick={handleSave} whileTap={{ scale: 0.85 }} style={{ marginLeft: 'auto' }}>
                                {saved ? <HiBookmark style={{ fontSize: 22 }} /> : <HiOutlineBookmark style={{ fontSize: 22 }} />}
                            </motion.button>
                        </div>
                        <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 4 }}>{likesCount.toLocaleString()} likes</div>
                        <div style={{ fontSize: 11, color: 'var(--text-3)', marginBottom: 10 }}>{timeago(post.createdAt)}</div>

                        {/* Comment input */}
                        <form onSubmit={handleComment} style={{ display: 'flex', alignItems: 'center', gap: 10, borderTop: '1px solid var(--border)', paddingTop: 10 }}>
                            <img src={user?.avatarUrl || `https://ui-avatars.com/api/?name=${user?.username}&background=6366F1&color=fff`}
                                style={{ width: 28, height: 28, borderRadius: '50%', objectFit: 'cover', flexShrink: 0 }} alt="" />
                            <div style={{ flex: 1, position: 'relative' }}>
                                {replyingTo && (
                                    <div style={{ position: 'absolute', bottom: '100%', left: 0, fontSize: 11, color: 'var(--text-3)', paddingBottom: 6 }}>
                                        Replying to <strong>{replyingTo.author?.username}</strong>
                                    </div>
                                )}
                                <input
                                    ref={inputRef}
                                    value={body} onChange={e => setBody(e.target.value)}
                                    placeholder={replyingTo ? 'Write a reply...' : 'Add a commentΓÇª'}
                                    style={{
                                        width: '100%', background: 'none', border: 'none', outline: 'none',
                                        color: 'var(--text-1)', fontSize: 14,
                                    }} />
                            </div>
                            {body.trim() && (
                                <button type="submit" style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--accent)', fontWeight: 700, fontSize: 13 }}>
                                    Post
                                </button>
                            )}
                        </form>
                    </div>
                </div>
            </div>

            {editOpen && (
                <EditPostModal
                    post={post}
                    onClose={() => setEditOpen(false)}
                    onSave={(updated) => { setPost(p => ({ ...p, ...updated })); setEditOpen(false) }}
                />
            )}
        </>
    )
}

import { useState, useEffect } from 'react'
import { useParams, useNavigate, Link } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import { motion, AnimatePresence } from 'framer-motion'
import api, { CHAT_BASE_URL } from '../api/axios'
import toast from 'react-hot-toast'
import { HiViewGrid, HiFilm, HiBookmark, HiHeart, HiChat, HiBadgeCheck, HiChatAlt2 } from 'react-icons/hi'
import UserListModal from '../components/UserListModal'
import EditProfileModal from '../components/EditProfileModal'
import { StoryViewer } from '../components/StoryRail'

function useCountUp(target, duration = 800) {
    const [count, setCount] = useState(0)
    useEffect(() => {
        if (!target) return
        const step = Math.ceil(target / (duration / 16))
        let current = 0
        const timer = setInterval(() => {
            current = Math.min(current + step, target)
            setCount(current)
            if (current >= target) clearInterval(timer)
        }, 16)
        return () => clearInterval(timer)
    }, [target, duration])
    return count
}

function StatItem({ value, label, onClick }) {
    const count = useCountUp(value)
    const fmt = (n) => n >= 1000000 ? (n / 1000000).toFixed(1) + 'M' : n >= 1000 ? (n / 1000).toFixed(1) + 'K' : n
    return (
        <div className="profile-stat" onClick={onClick} style={{ cursor: onClick ? 'pointer' : 'default' }}>
            <div className="profile-stat-num">{fmt(count)}</div>
            <div className="profile-stat-label">{label}</div>
        </div>
    )
}

export default function Profile() {
    const { id } = useParams()
    const { user: me } = useAuth()
    const navigate = useNavigate()
    const [profile, setProfile] = useState(null)
    const [posts, setPosts] = useState([])
    const [savedPosts, setSavedPosts] = useState([])
    const [savedLoading, setSavedLoading] = useState(false)
    const [tab, setTab] = useState('posts')
    const [loading, setLoading] = useState(true)
    const [following, setFollowing] = useState(false)
    const [messaging, setMessaging] = useState(false)
    const [showFollowers, setShowFollowers] = useState(false)
    const [showFollowing, setShowFollowing] = useState(false)
    const [editProfile, setEditProfile] = useState(false)
    const [hasStory, setHasStory] = useState(false)
    const [storyGroupData, setStoryGroupData] = useState(null)
    const [viewerOpen, setViewerOpen] = useState(false)

    const isMe = me?._id === id

    useEffect(() => {
        const fetchAll = async () => {
            setLoading(true)
            try {
                const [{ data: pd }, { data: postsD }] = await Promise.all([
                    api.get(`/users/${id}`),
                    api.get(`/users/${id}/posts`),
                ])
                setProfile(pd.data)
                setFollowing(pd.data.isFollowing)
                setPosts(postsD.data || [])
            } catch { toast.error('User not found') }
            finally { setLoading(false) }
        }
        fetchAll()
    }, [id])

    // Check if this profile user has active stories
    useEffect(() => {
        api.get('/stories').then(({ data }) => {
            const allStories = data.data || []
            // Find stories authored by the profile user
            const userStories = allStories.filter(s => s.author?._id === id || s.author === id)
            setHasStory(userStories.length > 0)
            if (userStories.length > 0) {
                // Build a group object that StoryViewer can use
                const author = userStories[0].author
                setStoryGroupData({ author: typeof author === 'object' ? author : { _id: id, username: profile?.username, avatarUrl: profile?.avatarUrl }, stories: userStories })
            }
        }).catch(() => { })
    }, [id]) // eslint-disable-line

    // Fetch saved posts only when Saved tab is opened (and only for own profile)
    useEffect(() => {
        if (tab !== 'saved' || !isMe) return
        setSavedLoading(true)
        api.get('/posts/saved')
            .then(({ data }) => setSavedPosts(data.data || []))
            .catch(() => setSavedPosts([]))
            .finally(() => setSavedLoading(false))
    }, [tab, isMe])

    const handleFollow = async () => {
        const was = following
        setFollowing(!was)
        setProfile(p => ({ ...p, followersCount: p.followersCount + (was ? -1 : 1) }))
        try {
            if (was) await api.delete(`/users/${id}/follow`)
            else await api.post(`/users/${id}/follow`)
        } catch {
            setFollowing(was)
            setProfile(p => ({ ...p, followersCount: p.followersCount + (was ? 1 : -1) }))
        }
    }

    // Start or open a conversation with this user
    const handleMessage = async () => {
        setMessaging(true)
        try {
            const { data } = await api.post(`conversations`, { targetUserId: id }, { baseURL: CHAT_BASE_URL })
            navigate(`/messages/${data.data._id}`)
        } catch (err) {
            toast.error(err.response?.data?.message || 'Could not open chat')
        } finally {
            setMessaging(false)
        }
    }

    if (loading) return (
        <div className="flex justify-center items-center" style={{ padding: '80px 0' }}>
            <div className="spinner" style={{ width: 36, height: 36 }} />
        </div>
    )
    if (!profile) return (
        <p style={{ color: 'var(--text-muted)', textAlign: 'center', padding: 60 }}>User not found</p>
    )

    const avatar = profile.avatarUrl || `https://ui-avatars.com/api/?name=${profile.username}&size=200&background=6366F1&color=fff`

    return (
        <div className="profile-page-wrap fade-in">
            {/* ΓöÇΓöÇ Header ΓöÇΓöÇ */}
            <div className="profile-header">

                {/* Avatar */}
                <div className="profile-avatar-col">
                    <div
                        onClick={() => hasStory && setViewerOpen(true)}
                        style={{
                            position: 'relative',
                            cursor: hasStory ? 'pointer' : 'default',
                            display: 'inline-block',
                        }}
                    >
                        {/* Gradient story ring ΓÇö only shown when user has stories */}
                        {hasStory && (
                            <div style={{
                                position: 'absolute',
                                inset: -3,
                                borderRadius: '50%',
                                background: 'linear-gradient(215deg, #6559CA 0%, #C13584 25%, #E1306C 50%, #F77737 75%, #FCAF45 100%)',
                                animation: 'rotateBorder 3s linear infinite',
                                padding: 2,
                                zIndex: 0,
                            }} />
                        )}
                        <div className={hasStory ? '' : 'profile-avatar-ring'} style={{
                            position: 'relative',
                            zIndex: 1,
                            borderRadius: '50%',
                            background: 'var(--bg)',
                            padding: hasStory ? 3 : 0,
                            display: 'inline-block',
                        }}>
                            <img
                                src={avatar}
                                alt={profile.username}
                                style={{
                                    width: hasStory ? 100 : undefined,
                                    height: hasStory ? 100 : undefined,
                                    borderRadius: '50%',
                                    objectFit: 'cover',
                                    display: 'block',
                                }}
                            />
                        </div>
                    </div>
                </div>

                {/* Info */}
                <div className="profile-info-col">

                    {/* Row 1: username + buttons */}
                    <div className="profile-username-row">
                        <h1>{profile.username}</h1>
                        {profile.isVerified && (
                            <HiBadgeCheck style={{ fontSize: 18, color: 'var(--accent)', flexShrink: 0 }} />
                        )}
                        {isMe ? (
                            <button className="btn btn-secondary btn-sm" onClick={() => setEditProfile(true)}>Edit profile</button>
                        ) : (
                            <>
                                <motion.button
                                    className={`btn btn-sm ${following ? 'btn-secondary' : 'btn-primary'}`}
                                    onClick={handleFollow}
                                    style={{ minWidth: 100 }}
                                    whileHover={{ scale: 1.03 }}
                                    whileTap={{ scale: 0.97 }}>
                                    {following ? 'Following' : 'Follow'}
                                </motion.button>
                                <motion.button
                                    className="btn btn-secondary btn-sm"
                                    onClick={handleMessage}
                                    disabled={messaging}
                                    style={{ display: 'flex', alignItems: 'center', gap: 6 }}
                                    whileHover={{ scale: 1.03 }}
                                    whileTap={{ scale: 0.97 }}>
                                    {messaging
                                        ? <span className="spinner" style={{ width: 14, height: 14 }} />
                                        : <><HiChatAlt2 /> Message</>
                                    }
                                </motion.button>
                            </>
                        )}
                    </div>

                    {/* Row 2: stats ΓÇö Instagram inline style */}
                    <div className="profile-stats">
                        <div className="profile-stat">
                            <span className="profile-stat-num">{posts.length}</span>
                            <span className="profile-stat-label">posts</span>
                        </div>
                        <div className="profile-stat" onClick={() => setShowFollowers(true)} style={{ cursor: 'pointer' }}>
                            <span className="profile-stat-num">{profile.followersCount || 0}</span>
                            <span className="profile-stat-label">followers</span>
                        </div>
                        <div className="profile-stat" onClick={() => setShowFollowing(true)} style={{ cursor: 'pointer' }}>
                            <span className="profile-stat-num">{profile.followingCount || 0}</span>
                            <span className="profile-stat-label">following</span>
                        </div>
                    </div>

                    {/* Row 3: name + bio + website */}
                    <div className="profile-bio-row">
                        {profile.fullName && <p className="profile-full-name">{profile.fullName}</p>}
                        {profile.bio && <p className="profile-bio">{profile.bio}</p>}
                        {profile.website && (
                            <a href={profile.website} target="_blank" rel="noreferrer" className="profile-website">
                                {profile.website}
                            </a>
                        )}
                    </div>

                </div>
            </div>

            {/* ΓöÇΓöÇ Tabs ΓöÇΓöÇ */}
            <div className="profile-tabs">
                {[
                    { key: 'posts', icon: <HiViewGrid />, label: 'Posts' },
                    { key: 'dscrolls', icon: <HiFilm />, label: 'Dscrolls' },
                    ...(isMe ? [{ key: 'saved', icon: <HiBookmark />, label: 'Saved' }] : []),
                ].map(({ key, icon, label }) => (
                    <button key={key} onClick={() => setTab(key)}
                        className={`profile-tab-btn ${tab === key ? 'active' : ''}`}>
                        {icon}
                        <span>{label}</span>
                    </button>
                ))}
            </div>

            {/* ΓöÇΓöÇ Grid ΓöÇΓöÇ */}
            {(() => {
                let displayPosts = []
                let emptyIcon = '≡ƒô╖'
                let emptyTitle = 'No posts yet'
                let emptyDesc = isMe ? 'Share your first photo or video' : ''
                let isLoading = false

                if (tab === 'posts') {
                    displayPosts = posts.filter(p => p.mediaType !== 'video')
                } else if (tab === 'dscrolls') {
                    displayPosts = posts.filter(p => p.mediaType === 'video')
                    emptyIcon = '≡ƒÄ¼'
                    emptyTitle = 'No Dscrolls yet'
                    emptyDesc = isMe ? 'Share your first video' : ''
                } else if (tab === 'saved') {
                    displayPosts = savedPosts
                    isLoading = savedLoading
                    emptyIcon = '≡ƒöû'
                    emptyTitle = isMe ? 'Nothing saved yet' : 'Private'
                    emptyDesc = isMe ? 'Save posts to view them here' : ''
                }

                if (isLoading) return (
                    <div className="flex justify-center" style={{ padding: 60 }}>
                        <div className="spinner" style={{ width: 36, height: 36 }} />
                    </div>
                )

                return (
                    <>
                        <div className="profile-grid">
                            {displayPosts.map((p, i) => (
                                <Link key={p._id} to={`/posts/${p._id}`} className="profile-grid-item"
                                    style={{ animationDelay: `${i * 40}ms` }}>
                                    {p.mediaType === 'video'
                                        ? <video src={p.mediaUrl} style={{ width: '100%', height: '100%', objectFit: 'cover' }} muted />
                                        : <img src={p.mediaUrl} alt="" loading="lazy" />
                                    }
                                    <div className="profile-grid-overlay">
                                        <span style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                                            <HiHeart /> {p.likesCount || 0}
                                        </span>
                                        <span style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                                            <HiChat /> {p.commentsCount || 0}
                                        </span>
                                    </div>
                                </Link>
                            ))}
                        </div>
                        {displayPosts.length === 0 && (
                            <div className="empty-state" style={{ paddingTop: 60 }}>
                                <div className="empty-state-icon">{emptyIcon}</div>
                                <p className="empty-state-title">{emptyTitle}</p>
                                {emptyDesc && <p className="empty-state-desc">{emptyDesc}</p>}
                            </div>
                        )}
                    </>
                )
            })()}

            <UserListModal
                isOpen={showFollowers}
                onClose={() => setShowFollowers(false)}
                title="Followers"
                userId={profile._id}
                type="followers"
            />
            <UserListModal
                isOpen={showFollowing}
                onClose={() => setShowFollowing(false)}
                title="Following"
                userId={profile._id}
                type="following"
            />
            {editProfile && (
                <EditProfileModal
                    profile={profile}
                    onClose={() => setEditProfile(false)}
                    onSave={(updated) => {
                        setProfile(p => ({ ...p, ...updated }))
                        setEditProfile(false)
                    }}
                />
            )}

            {/* Story viewer ΓÇö only shown when profile has active stories */}
            <AnimatePresence>
                {viewerOpen && storyGroupData && (
                    <StoryViewer
                        groups={[storyGroupData]}
                        startGroupIdx={0}
                        onClose={() => setViewerOpen(false)}
                    />
                )}
            </AnimatePresence>
        </div>
    )
}
